126	 *          when no change is applied (target missing / locked).
127	 *
128	 * @example
129	 *   // Two unlocked entries at 50/50; raise the first to 80 → second falls to 20.
130	 *   rebalance(
131	 *     [
132	 *       { id: 'a', share: new Decimal(50), locked: false },
133	 *       { id: 'b', share: new Decimal(50), locked: false },
134	 *     ],
135	 *     'a',
136	 *     new Decimal(80),
137	 *   );
138	 *   // → [{ id: 'a', share: 80, locked: false }, { id: 'b', share: 20, locked: false }]
139	 *
140	 * @example
141	 *   // One locked entry at 40; raising 'b' past 60 is clamped.
142	 *   rebalance(
143	 *     [
144	 *       { id: 'a', share: new Decimal(40), locked: true  },
145	 *       { id: 'b', share: new Decimal(30), locked: false },
146	 *       { id: 'c', share: new Decimal(30), locked: false },
147	 *     ],
148	 *     'b',
149	 *     new Decimal(90),
150	 *   );
151	 *   // → b clamped to 60, c falls to 0, a stays at 40
152	 */
