154	  entries: ShareEntry[],
155	  targetId: string,
156	  newValue: Decimal
157	): ShareEntry[] {
158	  // Target is missing or locked → nothing to do; return the input unchanged so
159	  // callers can use reference equality to skip a re-render.
160	  const target = entries.find((entry) => entry.id === targetId);
161	  if (!target || target.locked) {
162	    return entries;
163	  }
164	
165	  // Locked entries hold a fixed portion of the pie; we can only redistribute
166	  // what's left after setting them aside.
167	  const lockedSum = entries
168	    .filter((entry) => entry.locked)
169	    .reduce((sum, entry) => sum.plus(entry.share), ZERO);
170	
171	  // Clamp the requested value into the budget available to unlocked entries.
172	  let clamped = Decimal.max(ZERO, Decimal.min(ONE_HUNDRED, newValue));
173	  const maxForTarget = Decimal.max(ZERO, ONE_HUNDRED.minus(lockedSum));
174	  if (clamped.greaterThan(maxForTarget)) {
175	    // Requested value would exceed what's available after honoring locks.
176	    clamped = maxForTarget;
177	  }
178	
179	  // Gather unlocked siblings (everyone except the target and the locks) and
180	  // the remaining percentage they collectively need to absorb.
181	  const siblings = entries.filter(
182	    (entry) => entry.id !== targetId && !entry.locked
183	  );
184	  const remaining = ONE_HUNDRED.minus(clamped).minus(lockedSum);
185	  const siblingSum = siblings.reduce(
186	    (sum, entry) => sum.plus(entry.share),
187	    ZERO
188	  );
189	
190	  // Produce the next array preserving original order.
191	  return entries.map((entry) => {
192	    if (entry.id === targetId) {
193	      // This is the row the user just edited → write the clamped value.
194	      return { ...entry, share: clamped };
195	    }
196	
197	    if (entry.locked) {
198	      // Locked rows are invariants by definition; leave them untouched.
199	      return entry;
200	    }
201	
202	    if (siblingSum.isZero()) {
203	      // Siblings collectively sum to zero → proportional scaling would be 0/0,
204	      // so fall back to splitting the remainder evenly between them.
205	      const denominator = Math.max(siblings.length, 1);
206	      return { ...entry, share: remaining.div(denominator) };
207	    }
208	
209	    // General case: each sibling keeps its previous proportion of the
210	    // unlocked pool, scaled into the new `remaining` budget.
211	    const nextShare = entry.share.div(siblingSum).mul(remaining);
212	    return { ...entry, share: nextShare };
213	  });
214	}
